// Gmail trigger returns capital From/Subject at top level
var subject = $json.Subject || $json.subject || '';
var from = $json.From || $json.from || '';
var body = $json.textPlain || $json.textHtml || '';

// Try payload.headers as fallback
if ((!subject || !from) && $json.payload && $json.payload.headers) {
  var headers = $json.payload.headers;
  for (var i = 0; i < headers.length; i++) {
    if (headers[i].name === 'Subject' || headers[i].name === 'subject') subject = headers[i].value;
    if (headers[i].name === 'From' || headers[i].name === 'from') from = headers[i].value;
  }
}

// Use snippet as body fallback
if (!body) body = $json.snippet || '';

// Find OMEGO-XXXX-REQ-XX in subject or body
var regex = /[A-Z0-9-]+-REQ-\d+/i;
var match = subject.match(regex) || body.match(regex);
if (!match) throw new Error('Request ID not found. Subject: ' + subject);

var requestId = match[0].toUpperCase();

// Extract sender email
var emailRegex = /<(.+?)>|([\w.-]+@[\w.-]+\.\w+)/;
var emailMatch = from.match(emailRegex);
var senderEmail = emailMatch ? (emailMatch[1] || emailMatch[2]) : from;

return {
  json: {
    request_id: requestId,
    sender_email: senderEmail.toLowerCase().trim(),
    email_subject: subject,
    email_body: body,
    received_at: new Date().toISOString()
  }
};

