var openaiResponse = $json;
var aiResponseText = '';

if (openaiResponse.choices && openaiResponse.choices[0] && openaiResponse.choices[0].message) {
  aiResponseText = openaiResponse.choices[0].message.content;
} else {
  throw new Error('Could not find AI response: ' + JSON.stringify(openaiResponse));
}

var extractedData;
try {
  var cleanedResponse = aiResponseText.replace(/```json\n|```/g, '').trim();
  extractedData = JSON.parse(cleanedResponse);
} catch (e) {
  throw new Error('AI response is not valid JSON: ' + aiResponseText);
}

if (!extractedData.total_price || !extractedData.currency) {
  throw new Error('Missing required fields: total_price or currency');
}

// Force total_price to a real number — GPT sometimes returns '1200 USD' or a string
var price = parseFloat(String(extractedData.total_price).replace(/[^0-9.]/g, ''));
if (isNaN(price) || price <= 0 || price > 10000000) {
  throw new Error('Invalid total_price from AI: ' + extractedData.total_price);
}
extractedData.total_price = price;

// Force transit_days to integer if present
if (extractedData.transit_days) {
  var days = parseInt(extractedData.transit_days);
  extractedData.transit_days = isNaN(days) ? null : days;
}

var requestData = $('Code - Extract Request ID').first().json;
var forwarderData = $('PostgreSQL - Verify Forwarder').first().json;

var quotationId = requestData.request_id + '-' + forwarderData.forwarder_id.toString().split('-').pop();
var aiSummary = forwarderData.company_name + ' offers ' + extractedData.currency + ' ' + extractedData.total_price + ' for ' + (extractedData.transit_days || 'N/A') + ' days transit via ' + (extractedData.carrier || 'carrier TBD') + '.';

return {
  json: {
    quotation_id: quotationId,
    request_id: requestData.request_id,
    forwarder_id: forwarderData.forwarder_id,
    forwarder_email: forwarderData.email,
    forwarder_company: forwarderData.company_name,
    total_price: extractedData.total_price,
    currency: extractedData.currency,
    transit_days: extractedData.transit_days || null,
    validity_days: extractedData.validity_days || 7,
    carrier: extractedData.carrier || 'Not specified',
    service_type: extractedData.service_type || 'Not specified',
    surcharges: extractedData.surcharges || {},
    is_hazardous: extractedData.is_hazardous || false,
    is_stackable: extractedData.is_stackable !== false,
    needs_insurance: extractedData.needs_insurance || false,
    notes: extractedData.notes || '',
    ai_summary: aiSummary,
    raw_email: requestData.email_body,
    status: 'ACTIVE',
    received_at: requestData.received_at,
    expires_at: new Date(Date.now() + (extractedData.validity_days || 7) * 24 * 60 * 60 * 1000).toISOString()
  }
};
